--- a/cache.go
+++ b/cache.go
@@ -10,20 +10,34 @@
 type Cache struct {
-	m map[string]string
+	mu sync.RWMutex
+	m  map[string][]byte
+	cap int
 }

-func (c *Cache) Get(k string) string {
-	return c.m[k]
+func (c *Cache) Get(k string) ([]byte, bool) {
+	c.mu.RLock()
+	defer c.mu.RUnlock()
+	v, ok := c.m[k]
+	return v, ok
 }

-func (c *Cache) Set(k, v string) {
-	c.m[k] = v
+func (c *Cache) Set(k string, v []byte) {
+	c.mu.Lock()
+	defer c.mu.Unlock()
+	if len(c.m) >= c.cap {
+		for kk := range c.m { delete(c.m, kk); break }
+	}
+	c.m[k] = v
 }
